import { defineAgent } from "eve";

export default defineAgent({
  model: process.env.AGENT_MODEL ?? "anthropic/claude-sonnet-4.6",
  description:
    "Runs browser-driven QA on web app flows such as signup and onboarding, captures evidence, and returns concise Markdown reports."
});

import { defineSandbox } from "eve/sandbox";

export default defineSandbox({
  async bootstrap({ use }) {
    const sandbox = await use();
    await sandbox.run({
      command: "bash setup-agent-browser.sh"
    });
  },
  async onSession({ use }) {
    const sandbox = await use();
    await sandbox.run({
      command: "bash setup-agent-browser.sh"
    });
  }
});

import { defineEvalConfig } from "eve/evals";

export default defineEvalConfig({
  maxConcurrency: 1,
  timeoutMs: 120_000
});

export const websiteQaSmokePrompt = [
  "Test https://example.com.",
  "",
  "Goal: smoke-test the public homepage only. Do not sign up, submit forms, use payment, bypass CAPTCHA, or use credentials.",
  "First run bash setup-agent-browser.sh. Then use Agent Browser in the sandbox to open the page, inspect a snapshot, and capture one screenshot under reports/assets/example-home.png.",
  "Return a concise Markdown QA report. If browser automation is unavailable, report that blocker clearly instead of doing a static HTML or SEO audit."
].join("\n");

export const requiredReportSectionPatterns = [
  /Executive Summary/i,
  /What Was Checked/i,
  /Findings/i,
  /Screenshots?\s*\/?\s*Artifacts?/i,
  /Recommended Fixes/i,
  /Follow[- ]Up Test Prompt/i
] as const;

export const agentBrowserCommandPattern = /agent-browser/;

import { defineEval } from "eve/evals";
import { includes } from "eve/evals/expect";
import {
  agentBrowserCommandPattern,
  requiredReportSectionPatterns,
  websiteQaSmokePrompt
} from "../shared/website-qa-smoke.js";

export default defineEval({
  description:
    "Verifies the Website QA agent uses browser automation and returns the expected Markdown report shape.",
  tags: ["smoke", "website-qa"],
  async test(t) {
    await t.send(websiteQaSmokePrompt);

    t.completed();
    t.noFailedActions();
    t.calledTool("bash", { input: { command: agentBrowserCommandPattern } });
    t.check(t.reply, includes("example.com"));

    for (const section of requiredReportSectionPatterns) {
      t.messageIncludes(section);
    }
  }
});

import { defineAgent } from "@flue/runtime";

export default defineAgent(() => ({
  model: "anthropic/claude-sonnet-4-6",
  cwd: "/workspace",
  instructions:
    "Run browser-driven QA on a website or web app. Use the sandbox command capability to run npx agent-browser commands, inspect and interact with onboarding/signup flows, capture screenshots, and then return a concise Markdown QA report."
}));

import { z } from "zod";

export interface CampaignInsight {
  campaignId: string;
  campaignName: string;
  spend: number;
  conversions: number;
  cpa: number | null;
}

export interface CampaignRecommendation {
  campaignId: string;
  campaignName: string;
  severity: "info" | "watch" | "action";
  recommendation: string;
}

export const reviewFacebookCampaignsInputSchema = z.object({});

export type ReviewFacebookCampaignsInput = z.infer<typeof reviewFacebookCampaignsInputSchema>;

export async function reviewFacebookCampaigns(_input: ReviewFacebookCampaignsInput = {}) {
  const insights = await fetchCampaignInsights();
  return {
    insights,
    recommendations: recommendCampaignActions(insights),
  };
}

export async function fetchCampaignInsights(fetchImpl: typeof fetch = fetch): Promise<CampaignInsight[]> {
  const token = process.env.FB_ACCESS_TOKEN;
  const accountId = process.env.FB_AD_ACCOUNT_ID;
  if (!token || !accountId) {
    throw new Error("FB_ACCESS_TOKEN and FB_AD_ACCOUNT_ID are required");
  }

  const fields = "campaign_id,campaign_name,spend,actions";
  const url = new URL(`https://graph.facebook.com/v21.0/${accountId}/insights`);
  url.searchParams.set("fields", fields);
  url.searchParams.set("date_preset", "yesterday");
  url.searchParams.set("access_token", token);

  const response = await fetchImpl(url);
  if (!response.ok) {
    throw new Error(`Facebook Ads API failed: ${response.status} ${response.statusText}`);
  }

  const payload = (await response.json()) as { data?: Array<Record<string, unknown>> };
  return (payload.data ?? []).map((row) => {
    const conversions = extractConversions(row.actions);
    const spend = Number(row.spend ?? 0);
    return {
      campaignId: String(row.campaign_id ?? ""),
      campaignName: String(row.campaign_name ?? "Untitled campaign"),
      spend,
      conversions,
      cpa: conversions > 0 ? spend / conversions : null
    };
  });
}

export function recommendCampaignActions(insights: CampaignInsight[]): CampaignRecommendation[] {
  return insights.map((item) => {
    if (item.spend > 100 && item.conversions === 0) {
      return {
        campaignId: item.campaignId,
        campaignName: item.campaignName,
        severity: "action",
        recommendation: "Pause or narrow this campaign until conversion tracking and creative quality are reviewed."
      };
    }

    if (item.cpa !== null && item.cpa > 75) {
      return {
        campaignId: item.campaignId,
        campaignName: item.campaignName,
        severity: "watch",
        recommendation: "CPA is elevated. Review audience overlap and move budget toward better converting ad sets."
      };
    }

    return {
      campaignId: item.campaignId,
      campaignName: item.campaignName,
      severity: "info",
      recommendation: "No urgent action. Keep monitoring spend and conversion volume."
    };
  });
}

function extractConversions(actions: unknown): number {
  if (!Array.isArray(actions)) return 0;
  const conversion = actions.find((action) => {
    if (!action || typeof action !== "object") return false;
    return String((action as { action_type?: unknown }).action_type ?? "").includes("purchase");
  }) as { value?: unknown } | undefined;
  return Number(conversion?.value ?? 0);
}

import { defineAgent } from "eve";

export default defineAgent({
  model: process.env.AGENT_MODEL ?? "anthropic/claude-sonnet-4.6",
  description: "Reviews Facebook Ads performance and recommends daily optimization actions."
});

import { defineTool } from "eve/tools";
import {
  reviewFacebookCampaigns,
  reviewFacebookCampaignsInputSchema,
  type ReviewFacebookCampaignsInput,
} from "../lib/facebook.js";

export default defineTool({
  description: "Review yesterday's Facebook Ads campaign performance and return recommended actions.",
  inputSchema: reviewFacebookCampaignsInputSchema,
  async execute(input: ReviewFacebookCampaignsInput) {
    return reviewFacebookCampaigns(input);
  }
});

import { defineSchedule } from "eve/schedules";

export default defineSchedule({
  cron: "0 9 * * *",
  timezone: "UTC",
  prompt: "Run the Facebook Ads daily loop and summarize the recommended campaign actions."
});

